local SNAP_RADIUS = 10000     -- stale entries snap to a fresh 1.0 node within this range
local CELL = 10000            -- spatial index bucket size

local function safe(fn, dflt) local ok, v = pcall(fn) return ok and v or dflt end

-- ---------------------------------------------------------------- widgets --
local function findDescendant(w, name, depth)
    if not w or depth > 8 then return nil end
    if safe(function() return w:GetFName():ToString() end, "") == name then return w end
    local n = safe(function() return w:GetChildrenCount() end, 0) or 0
    for i = 0, n - 1 do
        local r = findDescendant(safe(function() return w:GetChildAt(i) end, nil), name, depth + 1)
        if r then return r end
    end
end

local function slotxy(w)
    local x, y
    pcall(function() local ld = w.Slot.LayoutData; x, y = ld.Offsets.Left, ld.Offsets.Top end)
    return x, y
end

local function pinsOfClass(canvas, cls)
    local pins = {}
    pcall(function()
        for i = 0, canvas:GetChildrenCount() - 1 do
            local c = canvas:GetChildAt(i)
            if safe(function() return c:GetClass():GetFName():ToString() end, "") == cls then
                local x, y = slotxy(c)
                if x then table.insert(pins, {x, y}) end
            end
        end
    end)
    return pins
end

-- returns the visible map's masked icon canvas
local function findMap()
    local canvas, bestScore = nil, 0
    for _, b in ipairs(FindAllOf("WBP_Map_Body_C") or {}) do
        pcall(function()
            if not b:IsValid() or not b:IsVisible() then return end
            local r = b.WidgetTree.RootWidget
            if not r or not r:IsValid() then return end
            local cv = findDescendant(r, "Canvas_ForIcon_Mask", 0)
            if not cv then return end
            local np = #pinsOfClass(cv, "WBP_Map_IconFTTower_C")
            if np + 1 > bestScore then bestScore = np + 1; canvas = cv end
        end)
    end
    return canvas
end

-- ------------------------------------------------------------- projection --
local function apply(t, wx, wy) return t[1]*wx + t[2]*wy + t[3] end

local function fitAffine(pairsM, sidx)
    local n = #pairsM
    if n < 5 then return nil end
    local mx, my, ms = 0, 0, 0
    for _, m in ipairs(pairsM) do mx = mx + m[1]; my = my + m[2]; ms = ms + m[sidx] end
    mx, my, ms = mx/n, my/n, ms/n
    local Cxx, Cxy, Cyy, Cxs, Cys = 0, 0, 0, 0, 0
    for _, m in ipairs(pairsM) do
        local dx, dy, ds = m[1]-mx, m[2]-my, m[sidx]-ms
        Cxx = Cxx+dx*dx; Cxy = Cxy+dx*dy; Cyy = Cyy+dy*dy
        Cxs = Cxs+dx*ds; Cys = Cys+dy*ds
    end
    local det = Cxx*Cyy - Cxy*Cxy
    if math.abs(det) < 1e-6 then return nil end
    local p = (Cxs*Cyy - Cys*Cxy) / det
    local q = (Cys*Cxx - Cxs*Cxy) / det
    return {p, q, ms - p*mx - q*my}
end

-- exact seed: match the 8 boss towers to the 8 boss pins (farthest pair,
-- 4 orientation hypotheses), then refine on the ~150 fast-travel statue pins
local function calibrate(canvas)
    local bp = pinsOfClass(canvas, "WBP_Map_IconTower_C")
    if #bp < 4 then return nil end
    local function farthest(set)
        local bi, bj, bd = 1, 2, -1
        for i = 1, #set do for j = i + 1, #set do
            local d = (set[i][1]-set[j][1])^2 + (set[i][2]-set[j][2])^2
            if d > bd then bd = d; bi = i; bj = j end
        end end
        return set[bi], set[bj]
    end
    local wA, wB = farthest(BOSSES)
    local pA, pB = farthest(bp)
    local tX, tY, bestErr = nil, nil, 1e18
    for _, axis in ipairs({true, false}) do
        for _, flip in ipairs({false, true}) do
            local qA, qB = pA, pB
            if flip then qA, qB = pB, pA end
            local wuA = axis and wA[2] or wA[1]
            local wuB = axis and wB[2] or wB[1]
            local wvA = axis and wA[1] or wA[2]
            local wvB = axis and wB[1] or wB[2]
            if math.abs(wuB - wuA) > 1 and math.abs(wvB - wvA) > 1 then
                local a = (qB[1]-qA[1]) / (wuB-wuA)
                local b = qA[1] - a*wuA
                local c = (qB[2]-qA[2]) / (wvB-wvA)
                local d = qA[2] - c*wvA
                local cX = axis and {0, a, b} or {a, 0, b}
                local cY = axis and {c, 0, d} or {0, c, d}
                local err = 0
                for _, t in ipairs(BOSSES) do
                    local px, py = apply(cX, t[1], t[2]), apply(cY, t[1], t[2])
                    local bd = 1e18
                    for _, q in ipairs(bp) do
                        local dd = (q[1]-px)^2 + (q[2]-py)^2
                        if dd < bd then bd = dd end
                    end
                    err = err + math.sqrt(bd)
                end
                if err < bestErr then bestErr = err; tX, tY = cX, cY end
            end
        end
    end
    if not tX then return nil end
    -- refine on statue pins (one matched least-squares pass is enough
    -- given the exact seed)
    local pins = pinsOfClass(canvas, "WBP_Map_IconFTTower_C")
    local pairsM = {}
    for _, t in ipairs(TOWERS) do
        local px, py = apply(tX, t[1], t[2]), apply(tY, t[1], t[2])
        local best, bd = nil, 60 * 60
        for _, p in ipairs(pins) do
            local d = (p[1]-px)^2 + (p[2]-py)^2
            if d < bd then bd = d; best = p end
        end
        if best then table.insert(pairsM, {t[1], t[2], best[1], best[2]}) end
    end
    if #pairsM >= 15 then
        local nX = fitAffine(pairsM, 3)
        local nY = fitAffine(pairsM, 4)
        if nX and nY then tX, tY = nX, nY end
    end
    print(string.format("[MapCollectablesFix] calibrated: boss residual %.0f px, %d statue anchors", bestErr, #pairsM))
    return {tX = tX, tY = tY}
end

-- ------------------------------------------------------- fresh data index --
local INDEX = {}   -- freshKey -> {buckets = {["i:j"] = {{x,y},...}}}
local function buildIndexes()
    for key, pts in pairs(V10) do
        local buckets = {}
        for _, p in ipairs(pts) do
            local k = math.floor(p[1]/CELL) .. ":" .. math.floor(p[2]/CELL)
            buckets[k] = buckets[k] or {}
            table.insert(buckets[k], p)
        end
        INDEX[key] = buckets
    end
end
local function snap(key, x, y)
    local buckets = INDEX[key]
    if not buckets then return x, y end
    local bi, bj = math.floor(x/CELL), math.floor(y/CELL)
    local best, bd = nil, SNAP_RADIUS * SNAP_RADIUS
    for i = bi-1, bi+1 do
        for j = bj-1, bj+1 do
            for _, p in ipairs(buckets[i .. ":" .. j] or {}) do
                local d = (p[1]-x)^2 + (p[2]-y)^2
                if d < bd then bd = d; best = p end
            end
        end
    end
    if best then return best[1], best[2] end
    return nil  -- node removed in 1.0: hide
end

-- -------------------------------------------------------------- checkboxes --
local function readCheckboxes()
    local out = {}
    local uis = FindAllOf("MapCollectablesUI_C") or {}
    local root = safe(function() return uis[#uis].WidgetTree.RootWidget end, nil)
    local function walk(w, depth)
        if not w or depth > 12 then return end
        if safe(function() return w:GetClass():GetFName():ToString() end, ""):find("CheckBox") then
            local nm = safe(function() return w:GetFName():ToString() end, "?"):lower()
            local st = safe(function() return w:IsChecked() end, nil)
            if st == nil then st = safe(function() return w:GetCheckedState() end, nil) end
            out[nm] = (st == true or st == 1)
        end
        local n = safe(function() return w:GetChildrenCount() end, 0) or 0
        for i = 0, n - 1 do walk(safe(function() return w:GetChildAt(i) end, nil), depth + 1) end
    end
    walk(root, 0)
    return out
end

-- ------------------------------------------------------------------ state --
local gCalib = nil          -- cached transform
local gCalibKey = nil       -- full name of the canvas it was computed for
local gLastSig = ""         -- change-detection signature
local gLastLive = 0         -- icons placed by the last repair
local gLastRepairClock = 0  -- os.clock() of the last repair
local gPrevCount = -1       -- widget count on the previous tick (debounce)
local gReg = {}             -- widgets we attached during the last repair

-- ----------------------------------------------------------------- repair --
-- Layer toggles are real checkboxes injected into the mod's own map panel
-- (UIVerticalBox), styled by copying an existing checkbox's WidgetStyle:
-- the default UMG style has empty brushes in shipped games (0-px, unclickable).
-- States persist to a small file next to the script.
local STATE_PATHS = {
    "../../../Mods/NativeMods/UE4SS/Mods/MapCollectablesFix/state.lua",
    "Mods/MapCollectablesFix/state.lua",
}
local gExtraCbs = {}
local function saveExtraState()
    for _, sp in ipairs(STATE_PATHS) do
        local f = io.open(sp, "w")
        if f then
            f:write("return {")
            for k, v in pairs(gExtraState) do f:write(string.format("%s=%s,", k, tostring(v))) end
            f:write("}")
            f:close()
            return
        end
    end
end
for _, sp in ipairs(STATE_PATHS) do
    local ok, saved = pcall(dofile, sp)
    if ok and type(saved) == "table" then
        for k, v in pairs(saved) do if gExtraState[k] ~= nil then gExtraState[k] = v end end
        break
    end
end

local function ensureExtraCheckboxes()
    gExtraCbs = {}
    local uis = FindAllOf("MapCollectablesUI_C") or {}
    local root = safe(function() return uis[#uis].WidgetTree.RootWidget end, nil)
    local vbox = root and findDescendant(root, "UIVerticalBox", 0)
    if not vbox then return end
    -- déjà présent sur cette instance d'UI ?
    for i = 0, vbox:GetChildrenCount() - 1 do
        local c = vbox:GetChildAt(i)
        local nm = safe(function() return c:GetFName():ToString() end, "")
        if nm:find("FixRow_") then
            local key = nm:sub(8)
            for j = 0, c:GetChildrenCount() - 1 do
                local w = c:GetChildAt(j)
                if safe(function() return w:GetClass():GetFName():ToString() end, "") == "CheckBox" then
                    gExtraCbs[key] = w
                end
            end
        end
    end
    if next(gExtraCbs) then return end
    -- modèles: une case du panneau + le TextBlock natif interne d'un BP_PalTextBlock
    local cbTemplate, txtTemplate = nil, nil
    local function findTemplates(w, depth)
        if (cbTemplate and txtTemplate) or not w or depth > 14 then return end
        local cls = safe(function() return w:GetClass():GetFName():ToString() end, "")
        if cls == "CheckBox" and not cbTemplate then cbTemplate = w end
        if cls == "TextBlock" and not txtTemplate then txtTemplate = w end
        local n = safe(function() return w:GetChildrenCount() end, 0) or 0
        for i = 0, n - 1 do findTemplates(safe(function() return w:GetChildAt(i) end, nil), depth + 1) end
        -- descendre aussi dans les UserWidgets (BP_PalTextBlock etc.)
        local inner = safe(function() return w.WidgetTree.RootWidget end, nil)
        if inner then findTemplates(inner, depth + 1) end
    end
    findTemplates(root, 0)
    -- copie de style vérifiée: struct entier puis brush par brush si besoin
    local function copyCheckboxStyle(dst, tpl)
        local function brushName(cb2, field)
            return safe(function()
                local ro = cb2.WidgetStyle[field].ResourceObject
                return ro and ro:IsValid() and ro:GetFName():ToString() or "nil"
            end, "?")
        end
        pcall(function() dst.WidgetStyle = tpl.WidgetStyle end)
        if brushName(dst, "UncheckedImage") == brushName(tpl, "UncheckedImage") and brushName(tpl, "UncheckedImage") ~= "nil" then
            return "struct"
        end
        local fields = {"CheckedImage","CheckedHoveredImage","CheckedPressedImage",
                        "UncheckedImage","UncheckedHoveredImage","UncheckedPressedImage",
                        "UndeterminedImage","UndeterminedHoveredImage","UndeterminedPressedImage",
                        "BackgroundImage","BackgroundHoveredImage","BackgroundPressedImage"}
        local okc = 0
        for _, f in ipairs(fields) do
            local done = pcall(function() dst.WidgetStyle[f] = tpl.WidgetStyle[f] end)
            if done then okc = okc + 1 end
        end
        pcall(function() dst.WidgetStyle.CheckBoxType = tpl.WidgetStyle.CheckBoxType end)
        if brushName(dst, "UncheckedImage") == brushName(tpl, "UncheckedImage") and brushName(tpl, "UncheckedImage") ~= "nil" then
            return "brushes(" .. okc .. ")"
        end
        return "ÉCHEC (tpl=" .. brushName(tpl, "UncheckedImage") .. " dst=" .. brushName(dst, "UncheckedImage") .. ")"
    end
    local cbClass = StaticFindObject("/Script/UMG.CheckBox")
    local hbClass = StaticFindObject("/Script/UMG.HorizontalBox")
    local txtClass = StaticFindObject("/Script/UMG.TextBlock")
    local imgClass = StaticFindObject("/Script/UMG.Image")
    if not (cbClass and cbClass:IsValid() and hbClass and hbClass:IsValid() and txtClass and txtClass:IsValid()) then return end
    local injected = 0
    for _, layer in ipairs(EXTRAS) do
        pcall(function()
            local row = StaticConstructObject(hbClass, vbox, FName("FixRow_" .. layer.key))
            -- libellé
            local label = StaticConstructObject(txtClass, row)
            label:SetText(FText(EXTRA_LABELS[layer.key] or layer.key))
            if txtTemplate and txtTemplate:IsValid() then
                pcall(function() label.Font = txtTemplate.Font end)
                pcall(function() label:SetColorAndOpacity(txtTemplate.ColorAndOpacity) end)
            end
            label:SetVisibility(3)
            local ls = row:AddChildToHorizontalBox(label)
            pcall(function() ls:SetPadding({Left = 8, Top = 2, Right = 4, Bottom = 2}) end)
            pcall(function() ls:SetSize({Value = 1.0, SizeRule = 1}) end)  -- Fill
            -- pastille de couleur
            if imgClass and imgClass:IsValid() then
                local dot = StaticConstructObject(imgClass, row)
                dot:SetColorAndOpacity(layer.color)
                dot:SetVisibility(3)
                pcall(function() dot:SetDesiredSizeOverride({X = 12.0, Y = 12.0}) end)
                pcall(function() dot.Brush.ImageSize = {X = 12.0, Y = 12.0} end)
                local ds = row:AddChildToHorizontalBox(dot)
                pcall(function() ds:SetPadding({Left = 2, Top = 6, Right = 2, Bottom = 6}) end)
                pcall(function() ds:SetVerticalAlignment(2) end)
            end
            -- case à cocher, style copié du panneau
            local cb = StaticConstructObject(cbClass, row)
            if cbTemplate and cbTemplate:IsValid() then
                local how = copyCheckboxStyle(cb, cbTemplate)
                print(string.format("[MapCollectablesFix] style %s: %s", layer.key, how))
            end
            cb:SetVisibility(0)
            cb:SetIsChecked(gExtraState[layer.key])
            local cs = row:AddChildToHorizontalBox(cb)
            pcall(function() cs:SetPadding({Left = 4, Top = 2, Right = 8, Bottom = 2}) end)
            row:SetVisibility(4)
            vbox:AddChildToVerticalBox(row)
            gExtraCbs[layer.key] = cb
            injected = injected + 1
        end)
    end
    print(string.format("[MapCollectablesFix] %d rangée(s) injectées (style copié: %s)", injected, tostring(cbTemplate ~= nil)))
end

local function readExtrasConfig()
    ensureExtraCheckboxes()
    local changed = false
    for key, cb in pairs(gExtraCbs) do
        local st = safe(function() return cb:IsChecked() end, nil)
        if st ~= nil then
            local v = (st == true or st == 1)
            if gExtraState[key] ~= v then gExtraState[key] = v; changed = true end
        end
    end
    if changed then saveExtraState() end
end

local function repair(reason)
    local canvas = findMap()
    if not canvas then return false end
    local key = safe(function() return canvas:GetFullName() end, nil)
    if not gCalib or key == nil or key ~= gCalibKey then
        gCalib = calibrate(canvas)
        gCalibKey = key
        if not gCalib then return false end
    end
    local cbs = readCheckboxes()
    local mgr = (FindAllOf("CollectablesManager_C") or {})[1]
    if not mgr then return false end
    gReg = {}
    local total = 0
    for _, spec in ipairs(ARRAYS) do
        local aname, lf, wf, key, obtf, actf, fresh = spec[1], spec[2], spec[3], spec[4], spec[5], spec[6], spec[7]
        local st = cbs["show" .. key .. "checkbox"]
        local enabled = (st == nil) or st
        local incColl = obtf and (cbs["includecollected" .. key .. "checkbox"] == true)
        local arr = safe(function() return mgr[aname] end, nil)
        local cnt = safe(function() return #arr end, 0) or 0
        for i = 1, cnt do
            pcall(function()
                local e = arr[i]
                local ww = e[wf]
                if not (ww and ww:IsValid()) then return end
                local show = enabled
                if show and obtf then
                    local obt = safe(function() return e[obtf] end, false) == true
                    if actf and not obt then
                        obt = safe(function()
                            local actor = e[actf]
                            return actor and actor:IsValid() and actor.bPickedInClient == true
                        end, false) == true
                    end
                    if obt and not incColl then show = false end
                end
                local lx, ly
                if show then
                    local ll = e[lf]
                    lx, ly = ll.X, ll.Y
                    if fresh then lx, ly = snap(fresh, lx, ly) end
                    if not lx then show = false end
                end
                if show then
                    local px = apply(gCalib.tX, lx, ly)
                    local py = apply(gCalib.tY, lx, ly)
                    if px ~= px or px < -2000 or px > 6000 or py < -2000 or py > 6000 then return end
                    -- skip if already attached at the right spot (cheap idempotence)
                    local s = ww.Slot
                    local attached = s and s:IsValid() and safe(function() return ww:GetParent() == canvas end, false)
                    if attached then
                        local cx, cy = slotxy(ww)
                        if cx and math.abs(cx - px) < 0.5 and math.abs(cy - py) < 0.5 then
                            total = total + 1
                            return
                        end
                    else
                        s = canvas:AddChildToCanvas(ww)
                        s:SetAlignment({X = 0.5, Y = 0.5})
                        s:SetAutoSize(true)
                        ww:SetVisibility(3)
                    end
                    s:SetPosition({X = px, Y = py})
                    table.insert(gReg, ww)
                    total = total + 1
                else
                    if safe(function() return ww:GetParent() == canvas end, false) then
                        ww:RemoveFromParent()
                    end
                end
            end)
        end
    end
    -- extra 1.0 layers: flat dots created on the fly (pooled by the GC cycle)
    do
        readExtrasConfig()
        local extraTotal = 0
        pcall(function()
            local tex = StaticFindObject("/Game/Mods/MapCollectablesMod/Images/Icons/quartzIcon.quartzIcon")
            if not (tex and tex:IsValid()) then
                pcall(function() tex = LoadAsset("/Game/Mods/MapCollectablesMod/Images/Icons/quartzIcon.quartzIcon") end)
            end
            if not (tex and tex:IsValid()) then
                tex = StaticFindObject("/Engine/EngineResources/WhiteSquareTexture.WhiteSquareTexture")
            end
            local imgClass = StaticFindObject("/Script/UMG.Image")
            if not (tex and tex:IsValid() and imgClass and imgClass:IsValid()) then
                print("[MapCollectablesFix] extras: texture/class not found, skipped")
                return
            end
            for _, layer in ipairs(EXTRAS) do
                if gExtraState[layer.key] then
                    for _, pt in ipairs(EXTRA_PTS[layer.key]) do
                        pcall(function()
                            local px = apply(gCalib.tX, pt[1], pt[2])
                            local py = apply(gCalib.tY, pt[1], pt[2])
                            if px ~= px or px < -2000 or px > 6000 or py < -2000 or py > 6000 then return end
                            local img = StaticConstructObject(imgClass, canvas)
                            if not (img and img:IsValid()) then return end
                            img:SetBrushFromTexture(tex, false)
                            img:SetColorAndOpacity(layer.color)
                            img:SetVisibility(3)
                            local s = canvas:AddChildToCanvas(img)
                            s:SetPosition({X = px, Y = py})
                            s:SetAlignment({X = 0.5, Y = 0.5})
                            s:SetAutoSize(false)
                            s:SetSize({X = 13, Y = 13})
                            table.insert(gReg, img)
                            extraTotal = extraTotal + 1
                        end)
                    end
                end
            end
        end)
        total = total + extraTotal
    end
    print(string.format("[MapCollectablesFix] %d icons placed (%s)", total, reason))
    gLastLive = total
    gLastRepairClock = os.clock()
    return true
end

-- ------------------------------------------------------------- automation --
-- Watches for the map being (re)opened or checkboxes changing. The mod
-- recreates its widgets on every map open, so the widget count is a reliable
-- change signal.
buildIndexes()
local gBusy = false
LoopAsync(800, function()
    if gBusy then return false end
    gBusy = true
    ExecuteInGameThread(function()
        local ok, err = pcall(function()
        local canvas = findMap()
        if not canvas then
            gLastSig = ""
            gPrevCount = -1
            -- restore the vanilla canvas: the game rebuilds/iterates its pin
            -- children on every open; leaving thousands of foreign widgets in
            -- there crashes the second open.
            if #gReg > 0 then
                local n = 0
                for _, ww in ipairs(gReg) do
                    pcall(function()
                        if ww and ww:IsValid() then ww:RemoveFromParent(); n = n + 1 end
                    end)
                end
                gReg = {}
                print(string.format("[MapCollectablesFix] map closed: detached %d icons", n))
            end
            -- housekeeping while idle: the original mod recreates all its icon
            -- widgets on every map open and never frees the old set. Collect
            -- only with the map closed and no recent repair (Slate at rest).
            if gLastLive > 0 and os.clock() - gLastRepairClock > 10 then
                local all = #(FindAllOf("CollectableWidget_C") or {})
                if all > gLastLive * 2 + 2000 then
                    gLastRepairClock = os.clock()  -- throttle
                    local ksl = StaticFindObject("/Script/Engine.Default__KismetSystemLibrary")
                    if ksl and ksl:IsValid() then
                        ksl:CollectGarbage()
                        ExecuteWithDelay(3000, function()
                            ExecuteInGameThread(function()
                              pcall(function()
                                local after = #(FindAllOf("CollectableWidget_C") or {})
                                print(string.format("[MapCollectablesFix] idle GC: %d -> %d widgets", all, after))
                              end)
                            end)
                        end)
                    end
                end
            end
            return
        end
        -- debounce: while the mod is still populating its arrays (widget count
        -- moving), do NOT touch them: a Blueprint-side TArray realloc during
        -- our iteration reads freed memory. Repair only once the count is
        -- stable across two consecutive ticks.
        local count = #(FindAllOf("CollectableWidget_C") or {})
        local stable = (count == gPrevCount)
        gPrevCount = count
        if not stable then return end
        local cbs = readCheckboxes()
        local h = tostring(count)
        for k, v in pairs(cbs) do h = h .. k .. tostring(v) end
        readExtrasConfig()
        for k, v in pairs(gExtraState) do h = h .. k .. tostring(v) end
        if h ~= gLastSig then
            gLastSig = h
            repair("auto")
        end
        end)
        gBusy = false
        if not ok then print("[MapCollectablesFix] watcher error: " .. tostring(err)) end
    end)
    return false
end)


RegisterKeyBind(Key.F7, function() gCalib = nil; gCalibKey = nil; repair("manual") end)
print("[MapCollectablesFix] loaded: auto-repair active (F7 = force refresh)")
